def _normalize_promocode_code(raw_code: str, max_len: int = 32) -> str:
    raw = str(raw_code or "").strip().upper()
    if not raw:
        return ""
    cleaned = "".join(ch for ch in raw if ch.isalnum() or ch in {"_", "-", "."})
    return cleaned[:max_len]

