    async def buy_property(self, user_id: int, property_id: int) -> tuple[bool, str, Optional[Dict[str, Any]]]:
        now = datetime.now().isoformat()
        async with self._connect() as db:
            db.row_factory = aiosqlite.Row
            await db.execute("BEGIN IMMEDIATE")
            async with db.execute("SELECT * FROM users WHERE user_id = ?", (int(user_id),)) as cursor:
                user = await cursor.fetchone()
            if not user:
                await db.rollback()
                return False, "Игрок не найден.", None

            async with db.execute("SELECT * FROM properties WHERE id = ?", (int(property_id),)) as cursor:
                prop = await cursor.fetchone()
            if not prop:
                await db.rollback()
                return False, "Объект недвижимости не найден.", None

            async with db.execute(
                "SELECT owner_id FROM property_ownership WHERE property_id = ? LIMIT 1",
                (int(property_id),),
            ) as cursor:
                owner_row = await cursor.fetchone()
            if owner_row:
                await db.rollback()
                return False, "Этот объект уже куплен другим игроком.", None

            price = float(prop["price"] or 0)
            balance = float(user["balance"] or 0)
            if balance < price:
                await db.rollback()
                return False, f"Недостаточно средств. Нужно ${price:,.2f}.", None

            new_balance = round(balance - price, 2)
            await db.execute(
                "UPDATE users SET balance = ?, property_owner = 1 WHERE user_id = ?",
                (new_balance, int(user_id)),
            )
            await db.execute(
                "INSERT INTO property_ownership (property_id, owner_id, acquired_date, last_rent_claimed) VALUES (?, ?, ?, ?)",
                (int(property_id), int(user_id), now, now),
            )
            await db.execute("UPDATE properties SET status = 'owned' WHERE id = ?", (int(property_id),))
            await db.commit()

        prop_data = dict(prop)
        await self.log_player_activity(
            user_id=user_id,
            activity_type="property_purchase",
            details=f"Куплена недвижимость: {prop_data.get('name')}",
            value=price,
        )
        return True, "Недвижимость успешно куплена.", {"property": prop_data, "new_balance": new_balance}

    async def sell_property(self, user_id: int, property_id: int) -> tuple[bool, str, Optional[Dict[str, Any]]]:
        """Продать свою недвижимость (если объект не занят бизнесом/частной организацией)."""
        now = datetime.now().isoformat()
        safe_user_id = int(user_id or 0)
        safe_property_id = int(property_id or 0)
        if safe_user_id <= 0 or safe_property_id <= 0:
            return False, "Некорректные параметры продажи.", None

        async with self._connect() as db:
            db.row_factory = aiosqlite.Row
            await db.execute("BEGIN IMMEDIATE")

            async with db.execute("SELECT balance FROM users WHERE user_id = ? LIMIT 1", (safe_user_id,)) as cursor:
                user_row = await cursor.fetchone()
            if not user_row:
                await db.rollback()
                return False, "Игрок не найден.", None

            async with db.execute(
                """
                SELECT p.*, po.id AS ownership_id
                FROM property_ownership po
                JOIN properties p ON p.id = po.property_id
                WHERE po.owner_id = ? AND po.property_id = ?
                LIMIT 1
                """,
                (safe_user_id, safe_property_id),
            ) as cursor:
                row = await cursor.fetchone()
            if not row:
                await db.rollback()
                return False, "Этот объект не принадлежит вам.", None

            async with db.execute(
                "SELECT 1 FROM businesses WHERE property_id = ? AND status = 'active' LIMIT 1",
                (safe_property_id,),
            ) as cursor:
                has_business = await cursor.fetchone() is not None
            async with db.execute(
                "SELECT 1 FROM private_orgs WHERE property_id = ? AND status = 'active' LIMIT 1",
                (safe_property_id,),
            ) as cursor:
                has_private_org = await cursor.fetchone() is not None
            if has_business or has_private_org:
                await db.rollback()
                return False, "Нельзя продать объект: в нем активен бизнес или частная организация.", None

            base_price = round(float(row["price"] or 0), 2)
            sell_price = round(max(0.0, base_price * 0.50), 2)
            balance_after = round(float(user_row["balance"] or 0) + sell_price, 2)

            await db.execute("DELETE FROM property_ownership WHERE id = ?", (int(row["ownership_id"]),))
            await db.execute(
                "UPDATE properties SET status = 'available' WHERE id = ?",
                (safe_property_id,),
            )
            await db.execute(
                "UPDATE users SET balance = ? WHERE user_id = ?",
                (balance_after, safe_user_id),
            )

            async with db.execute(
                "SELECT COUNT(*) FROM property_ownership WHERE owner_id = ?",
                (safe_user_id,),
            ) as cursor:
                own_count_row = await cursor.fetchone()
            own_count = int((own_count_row[0] if own_count_row else 0) or 0)
            await db.execute(
                "UPDATE users SET property_owner = ? WHERE user_id = ?",
                (1 if own_count > 0 else 0, safe_user_id),
            )
            await db.commit()

        prop_name = str(row["name"] or f"Объект #{safe_property_id}")
        await self.log_player_activity(
            user_id=safe_user_id,
            activity_type="property_sale",
            details=f"Продана недвижимость: {prop_name}",
            value=sell_price,
        )
        return True, "Недвижимость продана.", {
            "property_id": safe_property_id,
            "property_name": prop_name,
            "sale_price": sell_price,
            "new_balance": balance_after,
            "sold_at": now,
        }

    async def get_business_by_id(self, business_id: int) -> Optional[Dict[str, Any]]:
        async with self._connect() as db:
            db.row_factory = aiosqlite.Row
            async with db.execute("SELECT * FROM businesses WHERE id = ?", (int(business_id),)) as cursor:
                row = await cursor.fetchone()
                return dict(row) if row else None

    async def upgrade_business_equipment(
        self,
        owner_id: int,
        business_id: int,
    ) -> tuple[bool, str, Optional[Dict[str, Any]]]:
        safe_owner = int(owner_id or 0)
        safe_business = int(business_id or 0)
        if safe_owner <= 0 or safe_business <= 0:
            return False, "Некорректные параметры.", None

        async with self._connect() as db:
            db.row_factory = aiosqlite.Row
            await db.execute("BEGIN IMMEDIATE")
            async with db.execute(
                "SELECT * FROM businesses WHERE id = ? LIMIT 1",
                (safe_business,),
            ) as cursor:
                biz = await cursor.fetchone()
            if not biz:
                await db.rollback()
                return False, "Бизнес не найден.", None
            if int(biz["owner_id"] or 0) != safe_owner:
                await db.rollback()
                return False, "Только владелец может улучшать бизнес.", None

            level = int(biz["equipment_level"] or 1)
            budget = round(float(biz["budget"] or 0), 2)
            income_daily = round(float(biz["income_daily"] or 0), 2)
            expense_daily = round(float(biz["expense_daily"] or 0), 2)
            upgrade_cost = round(max(3_000.0, 2_500.0 * (level + 1)), 2)

            if budget < upgrade_cost:
                await db.rollback()
                return False, f"Недостаточно бюджета бизнеса. Нужно {upgrade_cost:,.2f} люмов.", None

            new_level = level + 1
            income_bonus = round(max(120.0, income_daily * 0.08), 2)
            expense_bonus = round(max(60.0, expense_daily * 0.04), 2)
            new_income = round(income_daily + income_bonus, 2)
            new_expense = round(expense_daily + expense_bonus, 2)
            new_budget = round(budget - upgrade_cost, 2)

            await db.execute(
                """
                UPDATE businesses
                SET equipment_level = ?,
                    income_daily = ?,
                    expense_daily = ?,
                    budget = ?
                WHERE id = ?
                """,
                (new_level, new_income, new_expense, new_budget, safe_business),
            )
            await db.commit()

        await self.log_player_activity(
            user_id=safe_owner,
            activity_type="business_upgrade",
            details=f"Улучшено оборудование бизнеса #{safe_business} до ур. {new_level}",
            value=upgrade_cost,
        )
        return True, "Оборудование улучшено.", {
            "business_id": safe_business,
            "level_before": level,
            "level_after": new_level,
            "upgrade_cost": upgrade_cost,
            "income_before": income_daily,
            "income_after": new_income,
            "expense_before": expense_daily,
            "expense_after": new_expense,
            "budget_after": new_budget,
        }

    async def list_user_businesses(self, owner_id: int) -> List[Dict[str, Any]]:
        async with self._connect() as db:
            db.row_factory = aiosqlite.Row
            async with db.execute(
                """
                SELECT b.*,
                       p.name AS property_name
                FROM businesses b
                LEFT JOIN properties p ON p.id = b.property_id
                WHERE b.owner_id = ?
                  AND COALESCE(b.status, 'active') = 'active'
                ORDER BY b.created_date DESC
                """,
                (int(owner_id),),
            ) as cursor:
                rows = await cursor.fetchall()
                return [dict(row) for row in rows]

    async def sell_business_to_system(
        self,
        owner_id: int,
        business_id: int,
    ) -> tuple[bool, str, Optional[Dict[str, Any]]]:
        safe_owner = int(owner_id or 0)
        safe_business = int(business_id or 0)
        if safe_owner <= 0 or safe_business <= 0:
            return False, "Некорректные параметры.", None

        now = datetime.now().isoformat()
        async with self._connect() as db:
            db.row_factory = aiosqlite.Row
            await db.execute("BEGIN IMMEDIATE")

            async with db.execute(
                "SELECT * FROM businesses WHERE id = ? AND COALESCE(status, 'active') = 'active' LIMIT 1",
                (safe_business,),
            ) as cursor:
                biz = await cursor.fetchone()
            if not biz:
                await db.rollback()
                return False, "Бизнес не найден или уже закрыт.", None
            if int(biz["owner_id"] or 0) != safe_owner:
                await db.rollback()
                return False, "Продать бизнес может только владелец.", None

            async with db.execute(
                "SELECT balance FROM users WHERE user_id = ? LIMIT 1",
                (safe_owner,),
            ) as cursor:
                owner_row = await cursor.fetchone()
            if not owner_row:
                await db.rollback()
                return False, "Игрок не найден.", None

            # Продажа системе за 50% оценочной стоимости бизнеса.
            budget = round(float(biz["budget"] or 0.0), 2)
            income_daily = round(float(biz["income_daily"] or 0.0), 2)
            expense_daily = round(float(biz["expense_daily"] or 0.0), 2)
            level = int(max(1, biz["equipment_level"] or 1))
            valuation = round(
                max(0.0, budget)
                + max(0.0, income_daily - expense_daily) * 18.0
                + level * 7_500.0,
                2,
            )
            sale_price = round(max(1_000.0, valuation * 0.5), 2)

            async with db.execute(
                """
                SELECT id, COALESCE(budget, 0) AS budget
                FROM organizations
                WHERE lower(COALESCE(type, '')) = 'government'
                ORDER BY id ASC
                LIMIT 1
                """
            ) as cursor:
                gov_row = await cursor.fetchone()
            if not gov_row:
                async with db.execute(
                    "SELECT id, COALESCE(budget, 0) AS budget FROM organizations WHERE name = 'Правительство' ORDER BY id ASC LIMIT 1"
                ) as cursor:
                    gov_row = await cursor.fetchone()
            if not gov_row:
                await db.rollback()
                return False, "Правительство не найдено.", None

            gov_id = int(gov_row["id"] or 0)
            gov_budget_before = round(float(gov_row["budget"] or 0.0), 2)
            if gov_budget_before < sale_price:
                await db.rollback()
                return False, "В госбюджете недостаточно средств для выкупа бизнеса.", {
                    "required": sale_price,
                    "government_budget": gov_budget_before,
                }

            owner_balance_before = round(float(owner_row["balance"] or 0.0), 2)
            owner_balance_after = round(owner_balance_before + sale_price, 2)
            gov_budget_after = round(gov_budget_before - sale_price, 2)

            await db.execute(
                "UPDATE users SET balance = ? WHERE user_id = ?",
                (owner_balance_after, safe_owner),
            )
            await db.execute(
                "UPDATE organizations SET budget = ? WHERE id = ?",
                (gov_budget_after, gov_id),
            )
            await db.execute(
                """
                UPDATE businesses
                SET status = 'sold_system',
                    budget = 0,
                    income_daily = 0,
                    expense_daily = 0,
                    last_income_date = ?
                WHERE id = ?
                """,
                (now, safe_business),
            )

            property_id = int(biz["property_id"] or 0)
            if property_id > 0:
                await db.execute(
                    "UPDATE properties SET status = 'owned' WHERE id = ?",
                    (property_id,),
                )

            async with db.execute(
                """
                SELECT COUNT(*) AS c
                FROM businesses
                WHERE owner_id = ?
                  AND COALESCE(status, 'active') = 'active'
                """,
                (safe_owner,),
            ) as cursor:
                active_left = int((await cursor.fetchone())["c"] or 0)
            await db.execute(
                "UPDATE users SET business_owner = ? WHERE user_id = ?",
                (1 if active_left > 0 else 0, safe_owner),
            )
            await db.commit()

        await self.log_player_activity(
            user_id=safe_owner,
            activity_type="business_sell_system",
            details=f"Бизнес #{safe_business} продан системе",
            value=sale_price,
        )
        return True, "Бизнес продан системе.", {
            "business_id": safe_business,
            "business_name": str(biz["name"] or f"Бизнес #{safe_business}"),
            "sale_price": sale_price,
            "valuation": valuation,
            "owner_balance_before": owner_balance_before,
            "owner_balance_after": owner_balance_after,
            "government_budget_before": gov_budget_before,
            "government_budget_after": gov_budget_after,
        }

    async def check_and_set_user_cooldown(
        self,
        user_id: int,
        action_key: str,
        cooldown_minutes: int,
    ) -> tuple[bool, int]:
        safe_key = " ".join((action_key or "").strip().split())[:80]
        if not safe_key:
            return True, 0

        safe_cooldown = max(1, min(int(cooldown_minutes or 1), 24 * 60))
        now_dt = datetime.now()
        now = now_dt.isoformat()

        async with self._connect() as db:
            db.row_factory = aiosqlite.Row
            await db.execute("BEGIN IMMEDIATE")
            async with db.execute(
                """
                SELECT last_used_at
                FROM user_action_cooldowns
                WHERE user_id = ? AND action_key = ?
                LIMIT 1
                """,
                (int(user_id), safe_key),
            ) as cursor:
                row = await cursor.fetchone()

            if row:
                last_dt = _parse_iso_datetime(row["last_used_at"])
                if last_dt:
                    remain = safe_cooldown - int((now_dt - last_dt).total_seconds() // 60)
                    if remain > 0:
                        await db.rollback()
                        return False, remain
                await db.execute(
                    """
                    UPDATE user_action_cooldowns
                    SET last_used_at = ?
                    WHERE user_id = ? AND action_key = ?
                    """,
                    (now, int(user_id), safe_key),
                )
            else:
                await db.execute(
                    """
                    INSERT INTO user_action_cooldowns (user_id, action_key, last_used_at)
                    VALUES (?, ?, ?)
                    """,
                    (int(user_id), safe_key, now),
                )
            await db.commit()
        return True, 0

    async def get_user_cooldown_remaining(
        self,
        user_id: int,
        action_key: str,
        cooldown_minutes: int,
    ) -> int:
        """Проверить оставшийся кулдаун (в минутах) без изменения таймера."""
        safe_key = " ".join((action_key or "").strip().split())[:80]
        if not safe_key:
            return 0
        safe_cooldown = max(1, min(int(cooldown_minutes or 1), 24 * 60))
        now_dt = datetime.now()
        async with self._connect() as db:
            db.row_factory = aiosqlite.Row
            async with db.execute(
                """
                SELECT last_used_at
                FROM user_action_cooldowns
                WHERE user_id = ? AND action_key = ?
                LIMIT 1
                """,
                (int(user_id), safe_key),
            ) as cursor:
                row = await cursor.fetchone()
        if not row:
            return 0
        last_dt = _parse_iso_datetime(row["last_used_at"])
        if not last_dt:
            return 0
        remain = safe_cooldown - int((now_dt - last_dt).total_seconds() // 60)
        return max(0, remain)

    async def get_business_resources(self, business_id: int) -> Dict[str, Any]:
        now = datetime.now().isoformat()
        async with self._connect() as db:
            db.row_factory = aiosqlite.Row
            async with db.execute(
                "SELECT id FROM businesses WHERE id = ? LIMIT 1",
                (int(business_id),),
            ) as cursor:
                exists = await cursor.fetchone()
            if not exists:
                return {
                    "business_id": int(business_id),
                    "raw_materials": 0.0,
                    "daily_consumption": 0.0,
                    "last_order_date": None,
                    "updated_date": now,
                }

            async with db.execute(
                "SELECT * FROM business_resources WHERE business_id = ? LIMIT 1",
                (int(business_id),),
            ) as cursor:
                row = await cursor.fetchone()
            if row:
                return dict(row)

            await db.execute(
                """
                INSERT INTO business_resources
                (business_id, raw_materials, daily_consumption, last_order_date, updated_date)
                VALUES (?, 0, 0, NULL, ?)
                """,
                (int(business_id), now),
            )
            await db.commit()
            return {
                "business_id": int(business_id),
                "raw_materials": 0.0,
                "daily_consumption": 0.0,
                "last_order_date": None,
                "updated_date": now,
            }

    async def order_business_raw_materials(
        self,
        owner_id: int,
        business_id: int,
        amount: float,
    ) -> tuple[bool, str, Optional[Dict[str, Any]]]:
        safe_amount = round(float(amount or 0), 2)
        if safe_amount <= 0:
            return False, "Количество сырья должно быть больше нуля.", None
        if safe_amount > 150_000:
            return False, "Слишком большой объем закупки.", None

        unit_price = 95.0
        total_cost = round(safe_amount * unit_price, 2)
        now = datetime.now().isoformat()
        async with self._connect() as db:
            db.row_factory = aiosqlite.Row
            await db.execute("BEGIN IMMEDIATE")
            async with db.execute(
                "SELECT * FROM businesses WHERE id = ? AND status = 'active' LIMIT 1",
                (int(business_id),),
            ) as cursor:
                business = await cursor.fetchone()
            if not business:
                await db.rollback()
                return False, "Бизнес не найден.", None
            if int(business["owner_id"] or 0) != int(owner_id):
                await db.rollback()
                return False, "Только владелец бизнеса может закупать сырье.", None

            budget = float(business["budget"] or 0)
            if budget < total_cost:
                await db.rollback()
                return False, f"Недостаточно бюджета бизнеса. Нужно ${total_cost:,.2f}.", None

            await db.execute(
                "UPDATE businesses SET budget = ? WHERE id = ?",
                (round(budget - total_cost, 2), int(business_id)),
            )
            await db.execute(
                """
                INSERT INTO business_resources
                (business_id, raw_materials, daily_consumption, last_order_date, updated_date)
                VALUES (?, ?, 0, ?, ?)
                ON CONFLICT(business_id) DO UPDATE SET
                    raw_materials = COALESCE(raw_materials, 0) + excluded.raw_materials,
                    last_order_date = excluded.last_order_date,
                    updated_date = excluded.updated_date
                """,
                (int(business_id), safe_amount, now, now),
            )
            await db.commit()

        await self.log_player_activity(
            user_id=owner_id,
            activity_type="business_raw_order",
            details=f"Закупка сырья для бизнеса #{int(business_id)}",
            value=total_cost,
        )
        return True, "Сырье для бизнеса закуплено.", {"amount": safe_amount, "total_cost": total_cost}

    async def transfer_business_funds(
        self,
        owner_id: int,
        business_id: int,
        amount: float,
        direction: str,
    ) -> tuple[bool, str, Optional[Dict[str, Any]]]:
        safe_amount = round(float(amount or 0), 2)
        if safe_amount <= 0:
            return False, "Сумма должна быть больше нуля.", None
        safe_direction = (direction or "").strip().lower()
        if safe_direction not in {"to_business", "to_owner"}:
            return False, "Некорректное направление перевода.", None

        async with self._connect() as db:
            db.row_factory = aiosqlite.Row
            await db.execute("BEGIN IMMEDIATE")
            async with db.execute("SELECT * FROM businesses WHERE id = ? LIMIT 1", (int(business_id),)) as cursor:
                business = await cursor.fetchone()
            if not business:
                await db.rollback()
                return False, "Бизнес не найден.", None
            if int(business["owner_id"] or 0) != int(owner_id):
                await db.rollback()
                return False, "Только владелец может переводить средства.", None

            async with db.execute("SELECT balance FROM users WHERE user_id = ? LIMIT 1", (int(owner_id),)) as cursor:
                user = await cursor.fetchone()
            if not user:
                await db.rollback()
                return False, "Владелец не найден.", None

            owner_balance = float(user["balance"] or 0)
            biz_budget = float(business["budget"] or 0)
            if safe_direction == "to_business":
                if owner_balance < safe_amount:
                    await db.rollback()
                    return False, "Недостаточно средств на личном счете.", None
                owner_balance = round(owner_balance - safe_amount, 2)
                biz_budget = round(biz_budget + safe_amount, 2)
            else:
                if biz_budget < safe_amount:
                    await db.rollback()
                    return False, "Недостаточно средств на счету бизнеса.", None
                owner_balance = round(owner_balance + safe_amount, 2)
                biz_budget = round(biz_budget - safe_amount, 2)

            await db.execute("UPDATE users SET balance = ? WHERE user_id = ?", (owner_balance, int(owner_id)))
            await db.execute("UPDATE businesses SET budget = ? WHERE id = ?", (biz_budget, int(business_id)))
            await db.commit()

        return True, "Перевод выполнен.", {
            "owner_balance": owner_balance,
            "business_budget": biz_budget,
            "amount": safe_amount,
            "direction": safe_direction,
        }

    async def run_business_operation(
        self,
        owner_id: int,
        business_id: int,
        operation: str,
    ) -> tuple[bool, str, Optional[Dict[str, Any]]]:
        op = (operation or "").strip().lower()
        if op not in {"production", "marketing", "contract"}:
            return False, "Неизвестная операция бизнеса.", None

        allowed, remain = await self.check_and_set_user_cooldown(
            owner_id,
            f"bizop:{int(business_id)}:{op}",
            20 if op == "contract" else 30,
        )
        if not allowed:
            return False, f"Кулдаун операции: еще {remain} мин.", {"cooldown_minutes": remain}

        now = datetime.now().isoformat()
        async with self._connect() as db:
            db.row_factory = aiosqlite.Row
            await db.execute("BEGIN IMMEDIATE")
            async with db.execute(
                "SELECT * FROM businesses WHERE id = ? AND status = 'active' LIMIT 1",
                (int(business_id),),
            ) as cursor:
                business = await cursor.fetchone()
            if not business:
                await db.rollback()
                return False, "Бизнес не найден.", None
            if int(business["owner_id"] or 0) != int(owner_id):
                await db.rollback()
                return False, "Только владелец может запускать операции.", None

            budget = float(business["budget"] or 0)
            income_daily = float(business["income_daily"] or 0)
            expense_daily = float(business["expense_daily"] or 0)
            equipment_level = max(1, int(business["equipment_level"] or 1))

            async with db.execute(
                "SELECT raw_materials FROM business_resources WHERE business_id = ? LIMIT 1",
                (int(business_id),),
            ) as cursor:
                res = await cursor.fetchone()
            raw_materials = float(res["raw_materials"] or 0) if res else 0.0

            delta_budget = 0.0
            delta_income = 0.0
            delta_expense = 0.0
            consumed = 0.0

            if op == "production":
                consumed = round(min(raw_materials, random.uniform(18.0, 55.0)), 2)
                if consumed <= 0:
                    await db.rollback()
                    return False, "Недостаточно сырья для производственной смены.", None
                produced_value = consumed * random.uniform(130.0, 210.0) * (1 + equipment_level * 0.04)
                delta_budget = round(produced_value - consumed * 35.0, 2)
                delta_income = round(max(0.0, consumed * 0.35), 2)
            elif op == "marketing":
                spend = round(min(budget, random.uniform(4_000.0, 18_000.0)), 2)
                if spend <= 0:
                    await db.rollback()
                    return False, "Недостаточно бюджета для маркетинга.", None
                effect = random.uniform(0.03, 0.11)
                delta_budget = -spend
                delta_income = round(income_daily * effect, 2)
                delta_expense = round(spend * 0.04, 2)
            else:  # contract
                cost = round(min(budget, random.uniform(2_000.0, 9_000.0)), 2)
                if cost <= 0:
                    await db.rollback()
                    return False, "Недостаточно бюджета для контракта.", None
                success = random.random() < 0.72
                if success:
                    gain = round(cost * random.uniform(1.4, 2.6), 2)
                    delta_budget = round(gain - cost, 2)
                    delta_income = round(gain * 0.08, 2)
                else:
                    delta_budget = -cost
                    delta_expense = round(cost * 0.06, 2)

            new_budget = round(max(0.0, budget + delta_budget), 2)
            new_income = round(max(120.0, income_daily + delta_income), 2)
            new_expense = round(max(80.0, expense_daily + delta_expense), 2)

            await db.execute(
                """
                UPDATE businesses
                SET budget = ?, income_daily = ?, expense_daily = ?, last_income_date = ?
                WHERE id = ?
                """,
                (new_budget, new_income, new_expense, now, int(business_id)),
            )
            if consumed > 0:
                await db.execute(
                    """
                    INSERT INTO business_resources (business_id, raw_materials, daily_consumption, last_order_date, updated_date)
                    VALUES (?, ?, ?, NULL, ?)
                    ON CONFLICT(business_id) DO UPDATE SET
                        raw_materials = MAX(0, COALESCE(raw_materials, 0) - ?),
                        daily_consumption = ?,
                        updated_date = excluded.updated_date
                    """,
                    (int(business_id), raw_materials, consumed, now, consumed, consumed),
                )
            await db.commit()

        await self.log_player_activity(
            user_id=owner_id,
            activity_type="business_operation",
            details=f"Операция {op} для бизнеса #{int(business_id)}",
            value=delta_budget,
        )
        try:
            await self.increment_business_daily_task_progress(
                business_id=int(business_id),
                increment=1,
            )
        except Exception:
            pass
        return True, "Операция бизнеса выполнена.", {
            "operation": op,
            "delta_budget": delta_budget,
            "new_budget": new_budget,
            "new_income_daily": new_income,
            "new_expense_daily": new_expense,
            "raw_consumed": consumed,
        }

